INSERT INTO `section_metas` VALUES (260,5,'title_top','About','2021-12-13 08:09:10','2021-12-13 08:09:10',NULL),(261,5,'title_bottom','Rizzy Home','2021-12-13 08:09:10','2021-12-13 08:09:10',NULL),(262,5,'description','The direct result of collaboration between two entrepreneurial brothers, Rizzy Home is the combined effort of Rizwan and Shamsu Ansari. Originally started as Rizzy Rugs and Home Texco, Rizzy Home now offers an extensive assortment of rugs.','2021-12-13 08:09:10','2021-12-13 08:09:10',NULL),(263,5,'video','https://www.youtube.com/embed/dgWzTvRhBkU','2021-12-13 08:09:10','2021-12-13 08:09:10',NULL),(782,2,'caption','Follow our blog for the latest trends, home tips, and touching stories from Textile Talker, Teresa','2021-12-21 07:11:50','2021-12-21 07:11:50',NULL),(783,2,'button_title','FIND OUT MORE','2021-12-21 07:11:50','2021-12-21 07:11:50',NULL),(784,2,'button_url','http://uat.lrhome.us/filters/NewArrivals','2021-12-21 07:11:50','2021-12-21 07:11:50',NULL),(785,2,'image','https://rizzyhome.botguys.ai/images/lets.jpg','2021-12-21 07:11:50','2021-12-21 07:11:50',NULL),(786,3,'caption',NULL,'2021-12-21 07:12:20','2021-12-21 07:12:20',NULL),(787,3,'prod_1_title','Rugs','2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(788,3,'prod_1_caption',NULL,'2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(789,3,'prod_1_image','https://vcs-images.botguys.ai/RizzyHome_B2BImages/Images/Full_Img/home-image-1.jpg','2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(790,3,'prod_1_url','http://uat.lrhome.us/favourites/1','2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(791,3,'prod_2_title','Pillows','2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(792,3,'prod_2_caption',NULL,'2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(793,3,'prod_2_image','https://vcs-images.botguys.ai/RizzyHome_B2BImages/Images/Full_Img/home-image-2.jpg','2021-12-21 07:12:21','2021-12-21 07:12:21',NULL),(794,3,'prod_2_url','http://uat.lrhome.us/favourites/2','2021-12-21 07:12:21','2021-12-21